import React, {  useEffect, useState } from "react";
import { useParams } from 'react-router-dom';
import { Button } from "antd";
import { BiEdit, BiStoreAlt } from "react-icons/bi";
import { AiFillDelete } from "react-icons/ai";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import {
  deleteStore,
  getEachUserStores,
  resetState,
} from "../../features/Store/StoreSlice";
import CustomModal from "../../components/CustomModal";

const EachMerchantStore = () => {
  const [open, setOpen] = useState(false);
  const [storeId, setStoreId] = useState("");
  const dispatch = useDispatch();
  const { id } = useParams()
  const storeState = useSelector((state) => state?.store?.stores); // Accessing store from Redux state

  // Function to show the modal
  const showModal = (id) => {
    setOpen(true);
    setStoreId(id);
  };

  // Function to hide the modal
  const hideModal = () => {
    setOpen(false);
    setStoreId("");
  };

  // Function to delete the store
  const deleteAStore = async (id) => {
    try {
      // Dispatching the delete store action
      await dispatch(deleteStore(id)).unwrap();
      toast.success("Store has been deleted!");

      // Fetch updated stores after deletion
      if (id) {
        await dispatch(getEachUserStores(id));
      } else {
        toast.error("Invalid user ID provided.");
      }
    } catch (error) {
      console.error("Error deleting store:", error);
      toast.error("Failed to delete the store.");
    } finally {
      hideModal();
    }
  };

  // Fetching the list of stores when component mounts
  useEffect(() => {
    const fetchStores = async () => {
      try {
        if (id) {
          await dispatch(getEachUserStores(id));
        } else {
          toast.error("Invalid user ID provided.");
        }
      } catch (error) {
        console.error("Error fetching stores:", error);
        toast.error("Failed to load stores.");
      }
    };

    fetchStores();
  }, [dispatch, id]);

  // Resetting state when component mounts
  useEffect(() => {
    dispatch(resetState());
  }, [dispatch]);

  return (
<div className="container mx-auto px-6 py-8">
   <h3 className="text-3xl font-semibold text-gray-900 mb-8">🌟 Stores</h3>
  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8">
    {storeState && storeState.length > 0 ? (
      storeState.map((store) => (
        <div key={store._id} className="bg-gray-800 text-white rounded-xl shadow-xl hover:scale-105 transform transition-all duration-300 ease-in-out p-6">
          <h4 className="text-2xl font-semibold mb-4 text-indigo-400">{store.storeName}</h4>
          <p className="text-gray-300 mb-4">
            <strong className="text-white">📍 Address:</strong> {store.address}
          </p>
          <div className="flex items-center justify-between space-x-4">
            <Link
              to={`store/${store._id}`}
              className="text-blue-400 hover:text-blue-600 font-medium transition-all duration-200"
            >
              <span className="inline-flex items-center space-x-2">
                <BiStoreAlt className="w-5 h-5" /> 
                <span>View Products</span>
              </span>
            </Link>
            <Button
              type="text"
              danger
              icon={<AiFillDelete />}
              className="text-red-400 hover:text-red-600 transition-all duration-200"
              onClick={() => showModal(store._id)}
            />
          </div>
        </div>
      ))
    ) : (
      <p className="text-center col-span-full text-gray-400">No stores found. 😞</p>
    )}
  </div>

  {/* Modal for Delete Confirmation */}
  <CustomModal
    hideModal={hideModal}
    open={open}
    performAction={() => deleteAStore(storeId)}
    title="⚠️ Are you sure you want to delete this store?"
    description="This action is irreversible."
  />
</div>

  );
};

export default EachMerchantStore;
